from typing import Literal

from fastapi import FastAPI, HTTPException, Path
from pydantic import BaseModel, ConfigDict, Field

app = FastAPI()
orders_train_1_store = {}


class CreateTrainOrders1(BaseModel):
    model_config = ConfigDict(extra="forbid")
    name: str = Field(min_length=1)
    status: Literal["active", "pending"] = "active"
    note: str | None = None


class PatchTrainOrders1(BaseModel):
    status: Literal["active", "pending", "archived"]


class TrainOrders1Item(BaseModel):
    model_config = ConfigDict(extra="forbid")
    id: int
    name: str
    status: Literal["active", "pending", "archived"]
    note: str | None = None


class TrainOrders1Envelope(BaseModel):
    items: list[TrainOrders1Item]
    total: int


def _create_orders_train_1(payload: CreateTrainOrders1) -> dict:
    item = {"id": len(orders_train_1_store) + 1, **payload.model_dump()}
    orders_train_1_store[item["id"]] = item
    return item


@app.post("/orders-t1", response_model=TrainOrders1Item, status_code=201)
def create_record(payload: CreateTrainOrders1):
    return _create_orders_train_1(payload)


@app.get("/orders-t1/{item_id}", response_model=TrainOrders1Item)
def get_record(item_id: int = Path(ge=1)):
    if item_id not in orders_train_1_store:
        raise HTTPException(status_code=404, detail="orders train missing 1")
    return orders_train_1_store[item_id]


@app.get("/orders-t1", response_model=TrainOrders1Envelope)
def list_orders_train_1_store():
    return {"items": list(orders_train_1_store.values()), "total": len(orders_train_1_store)}


@app.patch("/orders-t1/{item_id}", response_model=TrainOrders1Item)
def patch_record(payload: PatchTrainOrders1, item_id: int = Path(ge=1)):
    if item_id not in orders_train_1_store:
        raise HTTPException(status_code=404, detail="orders train missing 1")
    if orders_train_1_store[item_id]["status"] == "archived":
        raise HTTPException(status_code=409, detail="orders train conflict 1")
    orders_train_1_store[item_id]["status"] = payload.status
    return orders_train_1_store[item_id]

