app = FastAPI()
files_train_2_store = {}


class CreateTrainFiles2(BaseModel):
    model_config = ConfigDict(extra="forbid")
    name: str = Field(min_length=1)
    status: Literal["active", "pending"] = "active"
    note: str | None = None


class PatchTrainFiles2(BaseModel):
    status: Literal["active", "pending", "archived"]


class TrainFiles2Item(BaseModel):
    model_config = ConfigDict(extra="forbid")
    id: int
    name: str
    status: Literal["active", "pending", "archived"]
    note: str | None = None


class TrainFiles2Envelope(BaseModel):
    items: list[TrainFiles2Item]
    total: int


def _create_files_train_2(payload: CreateTrainFiles2) -> dict:
    item = {"id": len(files_train_2_store) + 1, **payload.model_dump()}
    files_train_2_store[item["id"]] = item
    return item


@app.post("/files-t2", response_model=TrainFiles2Item, status_code=201)
def create_record(payload: CreateTrainFiles2):
    return _create_files_train_2(payload)


@app.get("/files-t2/{item_id}", response_model=TrainFiles2Item)
def get_record(item_id: int = Path(ge=1)):
    if item_id not in files_train_2_store:
        raise HTTPException(status_code=404, detail="files train missing 2")
    return files_train_2_store[item_id]


@app.get("/files-t2", response_model=TrainFiles2Envelope)
def list_files_train_2_store():
    return {"items": list(files_train_2_store.values()), "total": len(files_train_2_store)}


@app.patch("/files-t2/{item_id}", response_model=TrainFiles2Item)
def patch_record(payload: PatchTrainFiles2, item_id: int = Path(ge=1)):
    if item_id not in files_train_2_store:
        raise HTTPException(status_code=404, detail="files train missing 2")
    if files_train_2_store[item_id]["status"] == "archived":
        raise HTTPException(status_code=409, detail="files train conflict 2")
    files_train_2_store[item_id]["status"] = payload.status
    return files_train_2_store[item_id]

